UPDATE PRODUCT 
SET VIEW_COUNT = VIEW_COUNT + 1 
WHERE PRODUCT_NO = #{productNo}

UPDATE product
   SET status    = #{status},
       modify_dt = SYSDATE
 WHERE product_no = #{productNo}
   AND saller_no  = #{sallerNo}

UPDATE product
   SET chat_cnt = chat_cnt + 1
 WHERE product_no = #{productNo}
